ALGORITHM ProducerConsumer
INPUT: buffer, mutex, empty, full
OUTPUT: none

BEGIN
 // Producer Process
 do {
 // Produce an item
 wait(empty);
 wait(mutex);
 // Add item to buffer
 signal(mutex);
 signal(full);
 } while (true);

 // Consumer Process
 do {
 wait(full);
 wait(mutex);
 // Remove item from buffer
 signal(mutex);
 signal(empty);
 // Consume the item
 } while (true);
END

#include <stdio.h>
#include <stdlib.h>
#include <pthread.h>
#include <semaphore.h>

// Initialize semaphores
sem_t chopsticks[5];

// Philosopher function
void* philosopher(void* arg) {
 int i = (int)arg;
 while (1) {
 // Think
 printf("Philosopher %d is thinking\n", i);
 sleep(1);

 // Pick up left chopstick
 sem_wait(&chopsticks[i]);

 // Pick up right chopstick
 sem_wait(&chopsticks[(i+1)%5]);

 // Eat
 printf("Philosopher %d is eating\n", i);
 sleep(1);

 // Put down right chopstick
 sem_post(&chopsticks[(i+1)%5]);

 // Put down left chopstick
 sem_post(&chopsticks[i]);
 }
 return NULL;
}

int main() {
 // Initialize semaphores
 for (int i = 0; i < 5; i++) {
 sem_init(&chopsticks[i], 0, 1);
 }

 // Create threads
 pthread_t threads[5];
 for (int i = 0; i < 5; i++) {
 pthread_create(&threads[i], NULL, philosopher, (void*)i);
 }

 // Wait for threads to finish
 for (int i = 0; i < 5; i++) {
 pthread_join(threads[i], NULL);
 }

 return 0;
}
